class Solution:
    def minNonZeroProduct(self, p):
        MOD = 10**9 + 7
        if p == 1:
            return 1
        mx = (1 << p) - 1
        base = mx - 1
        exp = (1 << (p - 1)) - 1
        return (mx % MOD) * pow(base % MOD, exp, MOD) % MOD

