var minNonZeroProduct = function(p) {
    const MOD = 1000000007n;
    if (p === 1) return 1;
    const mx = (1n << BigInt(p)) - 1n;
    let base = (mx - 1n) % MOD;
    let exp = (1n << BigInt(p - 1)) - 1n;
    let result = 1n;
    let b = base;
    let e = exp;
    while (e > 0n) {
        if (e & 1n) result = (result * b) % MOD;
        b = (b * b) % MOD;
        e >>= 1n;
    }
    return Number((mx % MOD) * result % MOD);
};
